const p1 = Promise.resolve(1);

const p2 = Promise.reject('error');

const p3 = Promise.resolve(3);

// Promise.all: fail fast — 1 fail là reject ngay

Promise.all([p1, p2, p3])

  .catch(err => console.log(err)); // 'error'

// Promise.allSettled: chờ tất cả, kể cả fail

Promise.allSettled([p1, p2, p3]).then(results => {

  results.forEach(r => {

    if (r.status === 'fulfilled') console.log('OK:', r.value);

    else console.log('FAIL:', r.reason);

  });

});

// OK: 1

// FAIL: error

// OK: 3

// Tag function

function highlight(strings, ...values) {

  return strings.map((str, i) => `${str}${values[i] ? `<b>${values[i]}</b>` : ''}`).join('');

}

const name = 'Dat';

const score = 95;

const result = highlight`Hello ${name}, your score is ${score}!`;

// 'Hello <b>Dat</b>, your score is <b>95</b>!'

