// Getter/Setter

const person = {

  _age: 25,

  get age() { return this._age; },

  set age(v) {

    if (v < 0) throw Error('Age cannot be negative');

    this._age = v;

  }

};

person.age; // 25

person.age = 30; // OK

person.age = -1; // Error

// Async iterator: từng bước có thể async

async function* asyncRange(from, to) {

  for (let i = from; i <= to; i++) {

    await new Promise(r => setTimeout(r, 100)); // simulate async

    yield i;

  }

}

// Consume

async function main() {

  for await (const num of asyncRange(1, 5)) {

    console.log(num); // 1, 2, 3, 4, 5 (mỗi cái cách 100ms)

  }

}

// Real-world: stream processing

async function processStream(readable) {

  for await (const chunk of readable) {

    processChunk(chunk);

  }

}
